with open(PATH, "r", encoding="utf-8") as f:
    data = json.load(f)

count = 0
for key, qs in QUESTIONS.items():
    if key not in data:
        print(f"⚠ {key} not found"); continue
    new_list = []
    for i, (qt, opts, correct_idx, expl) in enumerate(qs):
        options = []
        for j, o in enumerate(opts):
            text = o if isinstance(o, str) else o[0] if isinstance(o, list) else str(o)
            options.append({"text": text, "is_correct": j == correct_idx, "data_i18n": None})
        new_list.append({
            "question_number": i + 1,
            "question_text": qt,
            "attempted": 2,
            "data_i18n": None,
            "options": options,
            "explanation": expl
        })
    data[key]["quiz_questions"] = new_list
    count += 1

with open(PATH, "w", encoding="utf-8") as f:
    json.dump(data, f, indent=2, ensure_ascii=False)
print(f"✅ Integrated Science U1 quality re-fix: replaced questions for {count} lessons")
